#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new tree node
Node* createNode(int val) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to check if two trees are identical
int areIdenticalTrees(Node* root1, Node* root2) {
    if (root1 == NULL && root2 == NULL) {
        return 1;
    }
    if (root1 == NULL || root2 == NULL) {
        return 0;
    }
    return (root1->val == root2->val) &&
           areIdenticalTrees(root1->left, root2->left) &&
           areIdenticalTrees(root1->right, root2->right);
}

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    Node* root1 = NULL;
    Node* root2 = NULL;
    for (int i = 0; i < N - 1; i++) {
        int p, c;
        char R;
        scanf("%d %d %c", &p, &c, &R);
        // Create the tree nodes and assign them to root1
        if (root1 == NULL) {
            root1 = createNode(p);
        }
        Node* newNode = createNode(c);
        if (R == 'L') {
            root1->left = newNode;
        } else {
            root1->right = newNode;
        }
    }
    for (int i = 0; i < M - 1; i++) {
        int p, c;
        char R;
        scanf("%d %d %c", &p, &c, &R);
        // Create the tree nodes and assign them to root2
        if (root2 == NULL) {
            root2 = createNode(p);
        }
        Node* newNode = createNode(c);
        if (R == 'L') {
            root2->left = newNode;
        } else {
            root2->right = newNode;
        }
    }
    if (areIdenticalTrees(root1, root2)) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }
    return 0;
}

