        int val;
        Node left;
        Node right;

        Node(int val) {
            this.val = val;
            this.left = null;
            this.right = null;
        }
    }

    // Function to check if two trees are identical
    public static boolean areIdenticalTrees(Node root1, Node root2) {
        if (root1 == null && root2 == null) {
            return true;
        }
        if (root1 == null || root2 == null) {
            return false;
        }
        return (root1.val == root2.val) &&
               areIdenticalTrees(root1.left, root2.left) &&
               areIdenticalTrees(root1.right, root2.right);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int M = sc.nextInt();
        Node root1 = null;
        Node root2 = null;
        for (int i = 0; i < N - 1; i++) {
            int p = sc.nextInt();
            int c = sc.nextInt();
            char R = sc.next().charAt(0);
            // Create the tree nodes and assign them to root1
            if (root1 == null) {
                root1 = new Node(p);
            }
            Node newNode = new Node(c);
            if (R == 'L') {
                root1.left = newNode;
            } else {
                root1.right = newNode;
            }
        }
        for (int i = 0; i < M - 1; i++) {
            int p = sc.nextInt();
            int c = sc.nextInt();
            char R = sc.next().charAt(0);
            // Create the tree nodes and assign them to root2
